import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionVulnerable {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter the IP address to ping: ");
            String ipAddress = reader.readLine();

            // Vulnerable code - user input directly passed to the command without proper validation
            String command = "ping -c 3 " + ipAddress;
            Process process = Runtime.getRuntime().exec(command);

            BufferedReader resultReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = resultReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

